local assets = {Asset( "ANIM" , "anim/forcefield.zip" )} local function kill_fx(inst) inst.AnimState:PlayAnimation( "close" ) inst:DoTaskInTime(0.6, function() inst:Remove() end) end local function fn(Sim) local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() local sound = inst.entity:AddSoundEmitter() anim:SetBank( "forcefield" ) anim:SetBuild( "forcefield" ) anim:PlayAnimation( "open" ) anim:PushAnimation( "idle_loop" , true) anim:SetMultColour(0x0, 0x0, 0x0, 0x1) inst:AddTag( "noclick" ) inst.kill_fx = kill_fx return inst end return Prefab( "common/fx/dyc_fx_shadowshield" , fn, assets) 